    // MARK: - JavaScript Callback Helpers
    
    private func resolveJSCallback(callbackId: String, data: Any) {
        let sanitizedCallbackId = callbackId.replacingOccurrences(of: "'", with: "")
            .replacingOccurrences(of: "\\", with: "")
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: data),
