// MARK: - Secure Script Message Handler (avoids retain cycles)

class SecureScriptMessageHandler: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?
    
    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

// MARK: - WKScriptMessageHandler

extension HybridWebViewController: WKScriptMessageHandler {
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        
        // Validate origin
        guard isAllowedOrigin(message.frameInfo.request.url ?? webView.url) else {
            print("[HybridWebView] Blocked message from unauthorized origin: \(message.frameInfo.request.url?.absoluteString ?? "unknown")")
            return
        }
        
        // Only accept messages from main frame
        guard message.frameInfo.isMainFrame else {
            print("[HybridWebView] Blocked message from non-main frame")
            return
        }
        
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else {
            print("[HybridWebView] Invalid message format")
            return
        }
        
        let callbackId = body["callbackId"] as? String
        
        guard let handler = JSMessageHandler(rawValue: message.name) else {
            print("[HybridWebView] Unknown handler: \(message.name)")
            return
        }
        
        switch handler {
        case .camera:
            handleCameraMessage(action: action, body: body, callbackId: callbackId)
        case .pushNotification:
            handlePushNotificationMessage(action: action, callbackId: callbackId)
        case .inAppPurchase:
            handleInAppPurchaseMessage(action: action, body: body, callbackId: callbackId)
        case .nativeLog:
            handleLogMessage(body: body)
        }
    }
    
    // MARK: - Camera Handling
    
    private func handleCameraMessage(action: String, body: [String: Any], callbackId: String?) {
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }
            
            switch action {
            case "openCamera":
                self.requestCameraAccess { granted in
                    if granted {
                        self.presentImagePicker(sourceType: .camera, callbackId: callbackId)
                    } else {
                        if let cbId = callbackId {
                            self.rejectJSCallback(callbackId: cbId, error: "Camera access denied")
                        }
                        self.promptSettingsAccess(for: "Camera")
                    }
                }
                
            case "openPhotoLibrary":
                self.presentImagePicker(sourceType: .photoLibrary, callbackId: callbackId)
                
            default:
                if let cbId = callbackId {
                    self.rejectJSCallback(callbackId: cbId, error: "Unknown camera action")
                }
            }
        }
    }
    
    private func requestCameraAccess(completion: @escaping (Bool) -> Void) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        switch status {
        case .authorized:
            completion(true)
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { granted in
                DispatchQueue.main.async {
                    completion(granted)
                }
            }
        case .denied, .restricted:
            completion(false)
        @unknown default:
            completion(false)
        }
    }
    
    private func presentImagePicker(sourceType: UIImagePickerController.SourceType, callbackId: String?) {
        guard UIImagePickerController.isSourceTypeAvailable(sourceType) else {
            if let cbId = callbackId {
                rejectJSCallback(callbackId: cbId, error: "Source type not available")
            }
            return
        }
        
        let picker = UIImagePickerController()
        picker.sourceType = sourceType
        picker.delegate = self
        picker.allowsEditing = true
        picker.modalPresentationStyle = .fullScreen
        
        // Store callback ID for later use
        objc_setAssociatedObject(picker, &AssociatedKeys.callbackId, callbackId, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
        
        present(picker, animated: true)
    }
    
    private func promptSettingsAccess(for feature: String) {
        let alert = UIAlertController(
            title: "\(feature) Access Required",
            message: "Please enable \(feature.lowercased()) access in Settings to use this feature.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Settings", style: .default) { _ in
            if let settingsURL = URL(string: UIApplication.openSettingsURLString) {
                UIApplication.shared.open(settingsURL)
            }
        })
        present(alert, animated: true)
    }
    
    // MARK: - Push Notification Handling
    
    private func handlePushNotificationMessage(action: String, callbackId: String?) {
        switch action {
        case "requestPermission":
            UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
                if let error = error {
                    if let cbId = callbackId {
                        self?.rejectJSCallback(callbackId: cbId, error: error.localizedDescription)
                    }
                    return
                }
                
                if granted {
                    DispatchQueue.main.async {
                        UIApplication.shared.registerForRemoteNotifications()
                    }
                }
                
                if let cbId = callbackId {
                    self?.resolveJSCallback(callbackId: cbId, data: ["granted": granted])
                }
            }
            
        case "getToken":
            // Retrieve stored push token
            let token = UserDefaults.standard.string(forKey: "pushDeviceToken") ?? ""
            if let cbId = callbackId {
                if token.isEmpty {
                    rejectJSCallback(callbackId: cbId, error: "Push token not available. Request permission first.")
                } else {
                    resolveJSCallback(callbackId: cbId, data: ["token": token])
                }
            }
            
        default:
            if let cbId = callbackId {
                rejectJSCallback(callbackId: cbId, error: "Unknown push notification action")
            }
        }
    }
    
    // MARK: - In-App Purchase Handling
    
    private func handleInAppPurchaseMessage(action: String, body: [String: Any], callbackId: String?) {
        switch action {
        case "purchase":
            guard let productId = body["productId"] as? String,
                  isValidProductId(productId) else {
                if let cbId = callbackId {
                    rejectJSCallback(callbackId: cbId, error: "Invalid product ID")
                }
                return
            }
            purchaseManager?.purchase(productId: productId, callbackId: callbackId)
            
        case "getProducts":
            guard let productIds = body["productIds"] as? [String],
                  productIds.allSatisfy({ isValidProductId($0) }) else {
                if let cbId = callbackId {
                    rejectJSCallback(callbackId: cbId, error: "Invalid product IDs")
                }
                return
            }
            purchaseManager?.fetchProducts(productIds: Set(productIds), callbackId: callbackId)
            
        case "restore":
            purchaseManager?.restorePurchases(callbackId: callbackId)
            
        default:
            if let cbId = callbackId {
                rejectJSCallback(callbackId: cbId, error: "Unknown purchase action")
            }
        }
    }
    
    private func isValidProductId(_ productId: String) -> Bool {
        let pattern = "^[a-zA-Z0-9._]+$"
        return productId.range(of: pattern, options: .regularExpression) != nil && productId.count <= 100
    }
    
    // MARK: - Log Handling
    
    private func handleLogMessage(body: [String: Any]) {
        guard let message = body["message"] as? String else { return }
        let truncated = String(message.prefix(1000))
        print("[WebApp] \(truncated)")
    }
}

// MARK: - WKNavigationDelegate

extension HybridWebViewController: WKNavigationDelegate {
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        // Only allow HTTPS
        guard url.scheme == "https" else {
            // Allow about:blank for initial loads
            if url.scheme == "about" {
                decisionHandler(.allow)
                return
            }
            
            // Handle special schemes (tel, mailto)
            if let scheme = url.scheme, ["tel", "mailto"].contains(scheme) {
                UIApplication.shared.open(url)
                decisionHandler(.cancel)
                return
            }
            
            print("[HybridWebView] Blocked non-HTTPS navigation: \(url)")
            decisionHandler(.cancel)
            return
        }
        
        // Validate domain for main frame navigation
        if navigationAction.targetFrame?.isMainFrame == true {
            guard isAllowedOrigin(url) else {
                // Open external links in Safari
                UIApplication.shared.open(url)
                decisionHandler(.cancel)
                return
            }
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationResponse: WKNavigationResponse, decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void) {
        
        if let httpResponse = navigationResponse.response as? HTTPURLResponse {
            // Check for valid HTTP status codes
            if httpResponse.statusCode >= 400 {
                print("[HybridWebView] HTTP error: \(httpResponse.statusCode)")
            }
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        print("[HybridWebView] Page loaded: \(webView.url?.absoluteString ?? "unknown")")
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        let nsError = error as NSError
        // Ignore cancelled navigations
        if nsError.code == NSURLErrorCancelled { return }
        
        print("[HybridWebView] Navigation failed: \(error.localizedDescription)")
        showRetryAlert()
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        let nsError = error as NSError
        if nsError.code == NSURLErrorCancelled { return }
        
        print("[HybridWebView] Provisional navigation failed: \(error.localizedDescription)")
        showRetryAlert()
    }
    
    func webView(_ webView: WKWebView, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Validate the server certificate
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
    
    private func showRetryAlert() {
        let alert = UIAlertController(
            title: "Connection Error",
            message: "Unable to load the page. Please check your internet connection and try again.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Retry", style: .default) { [weak self] _ in
            self?.loadWebsite()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
}

// MARK: - WKUIDelegate

extension HybridWebViewController: WKUIDelegate {
    
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        // Handle target="_blank" links
        if let url = navigationAction.request.url {
            if isAllowedOrigin(url) {
                webView.load(navigationAction.request)
            } else {
                UIApplication.shared.open(url)
            }
        }
        return nil
    }
    
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        guard isAllowedOrigin(frame.request.url) else {
            completionHandler()
            return
        }
        
        let truncatedMessage = String(message.prefix(500))
        let alert = UIAlertController(title: nil, message: truncatedMessage, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        guard isAllowedOrigin(frame.request.url) else {
            completionHandler(false)
            return
        }
        
        let truncatedMessage = String(message.prefix(500))
        let alert = UIAlertController(title: nil, message: truncatedMessage, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    func webView(_ webView: WKWebView, runJavaScriptTextInputPanelWithPrompt prompt: String, defaultText: String?, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (String?) -> Void) {
        guard isAllowedOrigin(frame.request.url) else {
            completionHandler(nil)
            return
        }
        
        let truncatedPrompt = String(prompt.prefix(500))
        let alert = UIAlertController(title: nil, message: truncatedPrompt, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.text = defaultText
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(nil)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(alert.textFields?.first?.text)
        })
        present(alert, animated: true)
    }
}

// MARK: - UIImagePickerControllerDelegate

private struct AssociatedKeys {
    static var callbackId = "callbackId"
}

extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey: Any]) {
        let callbackId = objc_getAssociatedObject(picker, &AssociatedKeys.callbackId) as? String
        
        picker.dismiss(animated: true) { [weak self] in
            guard let self = self else { return }
            
            if let image = info[.editedImage] as? UIImage ?? info[.originalImage] as? UIImage {
                // Compress and convert to base64
                let maxSize: CGFloat = 1024
                let resizedImage = self.resizeImage(image, maxDimension: maxSize)
                
                if let imageData = resizedImage.jpegData(compressionQuality: 0.7) {
                    let base64String = imageData.base64EncodedString()
                    
                    if let cbId = callbackId {
                        self.resolveJSCallback(callbackId: cbId, data: [
                            "imageData": "data:image/jpeg;base64,\(base64String)",
                            "width": resizedImage.size.width,
                            "height": resizedImage.size.height
                        ])
                    }
                } else {
                    if let cbId = callbackId {
                        self.rejectJSCallback(callbackId: cbId, error: "Failed to process image")
                    }
                }
            } else {
                if let cbId = callbackId {
                    self.rejectJSCallback(callbackId: cbId, error: "No image selected")
                }
            }
        }
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        let callbackId = objc_getAssociatedObject(picker, &AssociatedKeys.callbackId) as? String
        
        picker.dismiss(animated: true) { [weak self] in
            if let cbId = callbackId {
                self?.rejectJSCallback(callbackId: cbId, error: "User cancelled")
            }
        }
    }
    
    private func resizeImage(_ image: UIImage, maxDimension: CGFloat) -> UIImage {
        let size = image.size
        
        guard size.width > maxDimension || size.height > maxDimension else {
            return image
        }
        
        let ratio = min(maxDimension / size.width, maxDimension / size.height)
        let newSize = CGSize(width: size.width * ratio, height: size.height * ratio)
        
        let renderer = UIGraphicsImageRenderer(size: newSize)
        return renderer.image { _ in
            image.draw(in: CGRect(origin: .zero, size: newSize))
        }
    }
}

// MARK: - In-App Purchase Manager

protocol InAppPurchaseManagerDelegate: AnyObject {
    func resolveJSCallback(callbackId: String, data: Any)
    func rejectJSCallback(callbackId: String, error: String)
}

extension HybridWebViewController: InAppPurchaseManagerDelegate {}

class InAppPurchaseManager: NSObject, SKProductsRequestDelegate, SKPaymentTransactionObserver {
    
    weak var delegate: InAppPurchaseManagerDelegate?
    
    private var products: [String: SKProduct] = [:]
    private var pendingCallbacks: [String: String] = [:] // action -> callbackId
    private var fetchCallbackId: String?
    private var restoreCallbackId: String?
    
    override init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }
    
    deinit {
        SKPaymentQueue.default().remove(self)
    }
    
    func fetchProducts(productIds: Set<String>, callbackId: String?) {
        fetchCallbackId = callbackId
        let request = SKProductsRequest(productIdentifiers: productIds)
        request.delegate = self
        request.start()
    }
    
    func purchase(productId: String, callbackId: String?) {
        guard SKPaymentQueue.canMakePayments() else {
            if let cbId = callbackId {
                delegate?.rejectJSCallback(callbackId: cbId, error: "In-app purchases are disabled on this device")
            }
            return
        }
        
        if let product = products[productId] {
            if let cbId = callbackId {
                pendingCallbacks[productId] = cbId
            }
            let payment = SKPayment(product: product)
            SKPaymentQueue.default().add(payment)
        } else {
            // Fetch product first, then purchase
            if let cbId = callbackId {
                pendingCallbacks[productId] = cbId
            }
            let request = SKProductsRequest(productIdentifiers: [productId])
            request.delegate = self
            request.start()
        }
    }
    
    func restorePurchases(callbackId: String?) {
        restoreCallbackId = callbackId
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
    
    // MARK: - SKProductsRequestDelegate
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        for product in response.products {
            products[product.productIdentifier] = product
        }
        
        if let cbId = fetchCallbackId {
            let productData = response.products.map { product -> [String: Any] in
                let formatter = NumberFormatter()
                formatter.numberStyle = .currency
                formatter.locale = product.priceLocale
                
                return [
                    "id": product.productIdentifier,
                    "title": product.localizedTitle,
                    "description": product.localizedDescription,
                    "price": product.price.doubleValue,
                    "priceFormatted": formatter.string(from: product.price) ?? "",
                    "currencyCode": product.priceLocale.currency?.identifier ?? ""
                ]
            }
            
            delegate?.resolveJSCallback(callbackId: cbId, data: [
                "products": productData,
                "invalidIds": response.invalidProductIdentifiers
            ])
            fetchCallbackId = nil
        }
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        if let cbId = fetchCallbackId {
            delegate?.rejectJSCallback(callbackId: cbId, error: error.localizedDescription)
            fetchCallbackId = nil
        }
    }
    
    // MARK: - SKPaymentTransactionObserver
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            let productId = transaction.payment.productIdentifier
            let callbackId = pendingCallbacks[productId]
            
            switch transaction.transactionState {
            case .purchased:
                // Validate receipt
                if let receiptURL = Bundle.main.appStoreReceiptURL,
                   let receiptData = try? Data(contentsOf: receiptURL) {
                    let receiptString = receiptData.base64EncodedString()
                    
                    if let cbId = callbackId {
                        delegate?.resolveJSCallback(callbackId: cbId, data: [
                            "status": "purchased",
                            "productId": productId,
                            "transactionId": transaction.transactionIdentifier ?? "",
                            "receipt": receiptString
                        ])
                    }
                }
                pendingCallbacks.removeValue(forKey: productId)
                queue.finishTransaction(transaction)
                
            case .failed:
                if let cbId = callbackId {
                    let errorMessage = transaction.error?.localizedDescription ?? "Purchase failed"
                    delegate?.rejectJSCallback(callbackId: cbId, error: errorMessage)
                }
                pendingCallbacks.removeValue(forKey: productId)
                queue.finishTransaction(transaction)
                
            case .restored:
                if let cbId = callbackId {
                    delegate?.resolveJSCallback(callbackId: cbId, data: [
                        "status": "restored",
                        "productId": productId,
                        "transactionId": transaction.transactionIdentifier ?? "",
                        "originalTransactionId": transaction.original?.transactionIdentifier ?? ""
                    ])
                }
                pendingCallbacks.removeValue(forKey: productId)
                queue.finishTransaction(transaction)
                
            case .deferred:
                if let cbId = callbackId {
                    delegate?.resolveJSCallback(callbackId: cbId, data: [
                        "status": "deferred",
                        "productId": productId
                    ])
                }
                
            case .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        if let cbId = restoreCallbackId {
            let restoredProducts = queue.transactions
                .filter { $0.transactionState == .restored }
                .map { $0.payment.productIdentifier }
            
            delegate?.resolveJSCallback(callbackId: cbId, data: [
                "status": "restored",
                "restoredProducts": restoredProducts
            ])
            restoreCallbackId = nil
        }
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        if let cbId = restoreCallbackId {
            delegate?.rejectJSCallback(callbackId: cbId, error: error.localizedDescription)
            restoreCallbackId = nil
        }
    }
}

// MARK: - AppDelegate Extension for Push Token

extension AppDelegate {
    func application(_ application: UIApplication, didRegisterForRemoteNotificationsWithDeviceToken deviceToken: Data) {
        let token = deviceToken.map { String(format: "%02.2hhx", $0) }.joined()
        UserDefaults.standard.set(token, forKey: "pushDeviceToken")
        print("[HybridApp] Push token: \(token)")
    }
    
    func application(_ application: UIApplication, didFailToRegisterForRemoteNotificationsWithError error: Error) {
        print("[HybridApp] Failed to register for push: \(error.localizedDescription)")
    }
}